            Document document = builder.parse(inputStream);
            document.getDocumentElement().normalize();
            
            Element root = document.getDocumentElement();
            String datasetType = root.getAttribute("type");
            
            LargeDatasetProcessor processor = new LargeDatasetProcessor();
            ProcessingResult result = processor.processDataset(root, datasetType);
            
            return createDatasetResponse(result);
